// contexts/StoreContext.tsx
import { createContext, useCallback, useContext, useState, Dispatch, SetStateAction } from 'react';
import { useAuth } from './AuthContext';

type StoreContextType = {
  theme: string;
  setTheme: Dispatch<SetStateAction<string>>;
  installPrompt: any; // Use the correct type for installPrompt
  setInstallPrompt: (prompt: any) => void; // Define the type for setInstallPrompt
};

const StoreContext = createContext<StoreContextType>({
  theme: 'dark',
  setTheme: () => {},
  installPrompt: null,
  setInstallPrompt: () => {},
});

export function useStore() {
  return useContext(StoreContext);
}

export function StoreProvider({ children }: { children: React.ReactNode }) {
  const { isAuthed } = useAuth();
  const [theme, setTheme] = useState('dark');
  const [installPrompt, setInstallPrompt] = useState<any>(null); // Initialize as null

  const handleBeforeInstallPrompt = useCallback((e: any) => {
    e.preventDefault();
    setInstallPrompt(e);
    return false;
  }, []);

  if (typeof window !== 'undefined') {
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }

  // Effect to clean up the event listener when the component unmounts
  // useEffect(() => {
  //   return () => {
  //     if (typeof window !== 'undefined') {
  //       window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  //     }
  //   };
  // }, [handleBeforeInstallPrompt]);

  return (
    <StoreContext.Provider value={{ theme, setTheme, installPrompt, setInstallPrompt }}>
      {children}
    </StoreContext.Provider>
  );
}
```

