## views/Negotiate.tsx

```tsx
import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Calculator, DollarSign, Package, Copy, Check, Search, User, FileText, RefreshCw, ChevronDown } from 'lucide-react';
import { useStore } from '../contexts/StoreContext';
import { Client } from '../types';

export const Negotiate: React.FC = () => {
  const { state } = useStore();
  const [activeTab, setActiveTab] = useState<'generator' | 'calculator'>('generator');

  // --- STATE FOR GENERATOR ---
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [clientSearch, setClientSearch] = useState('');
  const [isClientDropdownOpen, setIsClientDropdownOpen] = useState(false);

  const [productName, setProductName] = useState(''); // "10213 - CAFE MELITTA"
  const [quantity, setQuantity] = useState('');
  const [pricePalm, setPricePalm] = useState('');

  const [bonusProduct, setBonusProduct] = useState(''); // Defaults to productName
  const [bonusQty, setBonusQty] = useState('0');

  const [generatedText, setGeneratedText] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);

  const dropdownRef = useRef<HTMLDivElement>(null);

  // Filter Clients
  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
        c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
        c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  // Click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsClientDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Update bonus product name when main product changes (default behavior)
  useEffect(() => {
    if (!bonusProduct && productName) setBonusProduct(productName);
  }, [productName]);

  // --- CALCULATIONS ---
  const stats = useMemo(() => {
      const qty = parseInt(quantity) || 0;
      const price = parseFloat(pricePalm.replace(',', '.')) || 0;
      const bonus = parseInt(bonusQty) || 0;

      const totalValueSystem = qty * price;
      const totalUnits = qty + bonus;

      // Calculate effective price (weighted average)
      const finalPrice = totalUnits > 0 ? totalValueSystem / totalUnits : price;

      // Investment calculation: (Bonus Value / Total Potential Value) OR simple Qty based
      // Using the user's example logic: 10 buy + 1 bonus = 10% investment (1/10)
      const investmentPercent = qty > 0 ? (bonus / qty) * 100 : 0;
      const bonusValue = bonus * price;

      return {
          totalValueSystem,
          finalPrice,
          investmentPercent,
          bonusValue
      };
  }, [quantity, pricePalm, bonusQty]);

  const handleClientSelect = (client: Client) => {
      setSelectedClient(client);
      setClientSearch(`${client.code} - ${client.name}`);
      setIsClientDropdownOpen(false);
  };

  const generateText = () => {
      if (!selectedClient) {
          alert("Selecione um cliente");
          return;
      }

      const qty = parseInt(quantity) || 0;
      const text = `
Código/Produto: ${productName.toUpperCase()}
Quantidade: ${qty}
Valor pedido: R$ ${stats.totalValueSystem.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Preço Sistema: R$ ${(parseFloat(pricePalm.replace(',', '.'))||0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}

*Ação*

Código/Produto Bonificado: ${bonusProduct.toUpperCase() || productName.toUpperCase()}
Preço solicitado: R$ ${stats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Investimento: ${stats.investmentPercent.toFixed(1)}%
Quantidade bonificada: ${bonusQty} Und
Valor Bonificação: R$ ${stats.bonusValue.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Preço Final: R$ ${stats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2})}

Código/Razão do Cliente: ${selectedClient.name.toUpperCase()}
`.trim();

      setGeneratedText(text);
  };

  const copyToClipboard = () => {
      navigator.clipboard.writeText(generatedText);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
  };

  const clearForm = () => {
      setClientSearch('');
      setSelectedClient(null);
      setProductName('');
      setQuantity('');
      setPricePalm('');
      setBonusQty('0');
      setBonusProduct('');
      setGeneratedText('');
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-300 pb-24">

      {/* Header & Tabs */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <FileText className="text-brand-600" /> Negociação
            </h2>
            <p className="text-sm text-slate-500">Gerador de propostas e bonificações</p>
        </div>
        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
            <button 
                onClick={() => setActiveTab('generator')}
                className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'generator' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}
            >
                Gerador de Ação
            </button>
            <button 
                onClick={() => setActiveTab('calculator')}
                className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'calculator' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}
            >
                Calculadora Simples
            </button>
        </div>
      </div>

      {activeTab === 'generator' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

              {/* LEFT: INPUT FORM */}
              <div className="space-y-6">
                  {/* 1. Client Selection */}
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative z-20">
                      <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3 flex items-center gap-2">
                          <User size={14}/> Cliente
                      </h3>
                      <div className="relative" ref={dropdownRef}>
                          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                          <input 
                              type="text" 
                              value={clientSearch}
                              onChange={(e) => {
                                  setClientSearch(e.target.value);
                                  setIsClientDropdownOpen(true);
                                  if (selectedClient && e.target.value !== selectedClient.name) setSelectedClient(null);
                              }}
                              onFocus={() => setIsClientDropdownOpen(true)}
                              placeholder="Buscar cliente (Nome ou Código)..."
                              className={`w-full pl-9 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border ${selectedClient ? 'border-emerald-500 ring-1 ring-emerald-500' : 'border-slate-200 dark:border-slate-800'} rounded-xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-medium`}
                          />
                          {selectedClient && (
                              <div className="absolute right-3 top-1/2 -translate-y-1/2 text-emerald-600">
                                  <Check size={16} />
                              </div>
                          )}

                          {/* Dropdown List */}
                          {isClientDropdownOpen && (
                              <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-h-60 overflow-y-auto custom-scrollbar z-30">
                                  {filteredClients.length > 0 ? (
                                      filteredClients.map(client => (
                                          <button
                                              key={client.id}
                                              onClick={() => handleClientSelect(client)}
                                              className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 transition-colors"
                                          >
                                              <p className="font-bold text-sm text-slate-900 dark:text-white">{client.name}</p>
                                              <p className="text-xs text-slate-500">#{client.code} • {client.city}</p>
                                          </button>
                                      ))
                                  ) : (
                                      <div className="p-4 text-center text-xs text-slate-400">Nenhum cliente encontrado.</div>
                                  )}
                              </div>
                          )}
                      </div>
                  </div>

                  {/* 2. Product Data */}
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
                      <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3 flex items-center gap-2">
                          <Package size={14}/> Produto & Preço
                      </h3>

                      <div className="space-y-3">
                          <div>
                              <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Código / Produto</label>
                              <input 
                                  type="text" 
                                  value={productName}
                                  onChange={(e) => setProductName(e.target.value)}
                                  placeholder="Ex: 10213 - CAFE MELITTA"
                                  className="w-full px-3 py-2.5 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none focus:border-brand-500"
                              />
                          </div>

                          <div className="grid grid-cols-2 gap-3">
                              <div>
                                  <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Quantidade</label>
                                  <input 
                                      type="number" 
                                      value={quantity}
                                      onChange={(e) => setQuantity(e.target.value)}
                                      placeholder="10"
                                      className="w-full px-3 py-2.5 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none focus:border-brand-500"
                                  />
                              </div>
                              <div>
                                  <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Preço Palm (R$)</label>
                                  <div className="relative">
                                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">R$</span>
                                      <input 
                                          type="number" 
                                          value={pricePalm}
                                          onChange={(e) => setPricePalm(e.target.value)}
                                          placeholder="16,12"
                                          className="w-full pl-8 pr-3 py-2.5 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none focus:border-brand-500"
                                      />
                                  </div>
                              </div>
                          </div>
                      </div>
                  </div>

                  {/* 3. Action / Bonus */}
                  <div className="bg-gradient-to-br from-slate-900 to-slate-800 p-5 rounded-2xl shadow-lg text-white">
                      <h3 className="text-xs font-bold text-emerald-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                          <DollarSign size={14}/> Condição Comercial (Ação)
                      </h3>

                      <div className="space-y-3">
                          <div className="grid grid-cols-2 gap-3">
                              <div>
                                  <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Qtd. Bonificada</label>
                                  <input 
                                      type="number" 
                                      value={bonusQty}
                                      onChange={(e) => setBonusQty(e.target.value)}
                                      placeholder="1"
                                      className="w-full px-3 py-2.5 bg-white/10 border border-white/10 rounded-xl text-sm font-bold text-white outline-none focus:border-emerald-500"
                                  />
                              </div>
                              <div>
                                  <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Investimento</label>
                                  <div className="px-3 py-2.5 bg-white/5 rounded-xl border border-white/10 text-emerald-400 font-bold text-sm">
                                      {stats.investmentPercent.toFixed(1)}%
                                  </div>
                              </div>
                          </div>

                          <div>
                              <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Produto Bonificado (Opcional)</label>
                              <input 
                                  type="text" 
                                  value={bonusProduct}
                                  onChange={(e) => setBonusProduct(e.target.value)}
                                  placeholder="Se diferente do principal"
                                  className="w-full px-3 py-2.5 bg-white/10 border border-white/10 rounded-xl text-xs text-white outline-none focus:border-emerald-500 placeholder-white/30"
                              />
                          </div>

                          <div className="pt-2 mt-2 border-t border-white/10 flex justify-between items-center">
                              <span className="text-xs font-bold text-slate-300 uppercase">Preço Final</span>
                              <span className="text-2xl font-black tracking-tight text-white">R$ {stats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2, maximumFractionDigits: 2})}</span>
                          </div>
                      </div>
                  </div>

                  <div className="flex gap-3">
                      <button onClick={clearForm} className="px-4 py-3 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-500 hover:text-slate-700 font-bold text-sm transition-colors">
                          <RefreshCw size={18} />
                      </button>
                      <button onClick={generateText} className="flex-1 bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 rounded-xl shadow-lg shadow-brand-500/20 transition-transform active:scale-95 flex items-center justify-center gap-2">
                          <FileText size={18} /> Gerar Negociação
                      </button>
                  </div>
              </div>

              {/* RIGHT: RESULT */}
              <div className="space-y-4">
                  <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm h-full flex flex-col">
                      <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-950/50 rounded-t-2xl">
                          <h3 className="font-bold text-sm text-slate-700 dark:text-slate-300">Resultado Gerado</h3>
                          <button 
                              onClick={copyToClipboard} 
                              disabled={!generatedText}
                              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
