import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Calculator, DollarSign, Package, Copy, Check, Search, User, FileText, RefreshCw, ChevronDown, Handshake, Percent, RotateCcw, TrendingDown, TrendingUp, Gift } from 'lucide-react';
import { useStore } from '../contexts/StoreContext';
import { Client } from '../types';

