  // Bonus State
  const [bonusProduct, setBonusProduct] = useState(''); // Defaults to productName
  const [bonusQty, setBonusQty] = useState('0');

  // Discount State
  const [targetPrice, setTargetPrice] = useState(''); // The price the user WANTS to sell at

  const [generatedText, setGeneratedText] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);

  const dropdownRef = useRef<HTMLDivElement>(null);

  // --- STATE FOR CALCULATOR (Legacy) ---
  const [calcListPrice, setCalcListPrice] = useState<string>('');
  const [calcCost, setCalcCost] = useState<string>('');
  const [calcDiscount, setCalcDiscount] = useState<string>('');
  const [calcQty, setCalcQty] = useState<string>('1');
  const [calcTax, setCalcTax] = useState<string>('');

  // Filter Clients
  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
        c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
        c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  // Click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsClientDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Update bonus product name when main product changes (default behavior)
  useEffect(() => {
    if (!bonusProduct && productName) setBonusProduct(productName);
  }, [productName]);

  // When switching to discount mode, pre-fill target price with current price if empty
  useEffect(() => {
      if (negotiationType === 'discount' && !targetPrice && pricePalm) {
          setTargetPrice(pricePalm);
      }
  }, [negotiationType, pricePalm]);

  // --- GENERATOR CALCULATIONS ---
  const genStats = useMemo(() => {
      const qty = parseInt(quantity) || 0;
      const price = parseFloat(pricePalm.replace(',', '.')) || 0;

      let finalPrice = price;
      let investmentPercent = 0;
      let bonusValue = 0;
      let totalValueSystem = qty * price;

      if (negotiationType === 'bonus') {
          const bonus = parseInt(bonusQty) || 0;
          const totalUnits = qty + bonus;

          // Weighted Average Price
          finalPrice = totalUnits > 0 ? totalValueSystem / totalUnits : price;

          // Investment: Bonus Units / Sold Units (Trade Definition)
          investmentPercent = qty > 0 ? (bonus / qty) * 100 : 0;
          bonusValue = bonus * price;

      } else {
          // Discount Mode
          const target = parseFloat(targetPrice.replace(',', '.')) || price;
          finalPrice = target;

          // Investment: Discount % off the list price
          investmentPercent = price > 0 ? ((price - target) / price) * 100 : 0;
          bonusValue = (price - target) * qty; // Total discount value given
      }

      return {
          totalValueSystem,
          finalPrice,
          investmentPercent,
          bonusValue,
          isNegative: finalPrice < 0
      };
  }, [quantity, pricePalm, bonusQty, targetPrice, negotiationType]);

  // --- SIMPLE CALCULATOR CALCULATIONS ---
  const calcStats = useMemo(() => {
    const price = parseFloat(calcListPrice.replace(',', '.')) || 0;
    const unitCost = parseFloat(calcCost.replace(',', '.')) || 0;
    const disc = parseFloat(calcDiscount.replace(',', '.')) || 0;
    const qty = parseInt(calcQty) || 1;
    const taxRate = parseFloat(calcTax.replace(',', '.')) || 0;

    const discountValue = price * (disc / 100);
    const finalUnitPrice = price - discountValue;
    const taxValue = finalUnitPrice * (taxRate / 100);
    const netUnitPrice = finalUnitPrice - taxValue;

    const totalDealValue = finalUnitPrice * qty;
    const marginValue = (netUnitPrice - unitCost) * qty;
    const marginPercent = finalUnitPrice > 0 ? (marginValue / totalDealValue) * 100 : 0;

    return { price, finalUnitPrice, totalDealValue, discountValue, marginValue, marginPercent, netUnitPrice };
  }, [calcListPrice, calcCost, calcDiscount, calcQty, calcTax]);

  const handleClientSelect = (client: Client) => {
      setSelectedClient(client);
      setClientSearch(`${client.code} - ${client.name}`);
      setIsClientDropdownOpen(false);
  };

  const generateText = () => {
      if (!selectedClient) {
          alert("Selecione um cliente");
          return;
