      const qty = parseInt(quantity) || 0;

      let actionBlock = '';
      if (negotiationType === 'bonus') {
          actionBlock = `
Código/Produto Bonificado: ${bonusProduct.toUpperCase() || productName.toUpperCase()}
Preço solicitado (Médio): R$ ${genStats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Investimento: ${genStats.investmentPercent.toFixed(1)}%
Quantidade bonificada: ${bonusQty} Und
Valor Bonificação: R$ ${genStats.bonusValue.toLocaleString('pt-BR', {minimumFractionDigits: 2})}`;
