          actionBlock = `
Tipo de Ação: DESCONTO EM PREÇO
Preço Tabela: R$ ${(parseFloat(pricePalm.replace(',', '.'))||0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Preço Solicitado: R$ ${genStats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Desconto Aplicado: ${genStats.investmentPercent.toFixed(1)}%
Investimento Total: R$ ${genStats.bonusValue.toLocaleString('pt-BR', {minimumFractionDigits: 2})}`;
      }

      const text = `
Código/Produto: ${productName.toUpperCase()}
Quantidade: ${qty}
Valor Tabela Total: R$ ${genStats.totalValueSystem.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Preço Sistema Unit.: R$ ${(parseFloat(pricePalm.replace(',', '.'))||0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}

*Ação Comercial*
${actionBlock.trim()}

Preço Final Cliente: R$ ${genStats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2})}

Código/Razão do Cliente: ${selectedClient.name.toUpperCase()}
`.trim();

      setGeneratedText(text);
  };

  const copyToClipboard = () => {
