  const [bonusProduct, setBonusProduct] = useState(''); 
  const [bonusQty, setBonusQty] = useState('0');
  const [bonusProductPrice, setBonusProductPrice] = useState(''); // Value of the DIFFERENT product

  // Discount State
  const [targetPrice, setTargetPrice] = useState(''); // The price the user WANTS to sell at

  const [generatedText, setGeneratedText] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);

  const dropdownRef = useRef<HTMLDivElement>(null);

  // --- STATE FOR CALCULATOR (Legacy) ---
  const [calcListPrice, setCalcListPrice] = useState<string>('');
  const [calcCost, setCalcCost] = useState<string>('');
  const [calcDiscount, setCalcDiscount] = useState<string>('');
