  const [negotiationType, setNegotiationType] = useState<'bonus' | 'discount'>('bonus');

  // Bonus State
  const [bonusType, setBonusType] = useState<'same' | 'different'>('same');
  const [bonusProduct, setBonusProduct] = useState(''); 
  const [bonusQty, setBonusQty] = useState('0');
  const [bonusProductPrice, setBonusProductPrice] = useState(''); // Value of the DIFFERENT product

  // Discount State
  const [targetPrice, setTargetPrice] = useState(''); // The price the user WANTS to sell at

  const [generatedText, setGeneratedText] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);

  const dropdownRef = useRef<HTMLDivElement>(null);

  // --- STATE FOR CALCULATOR (Legacy) ---
  const [calcListPrice, setCalcListPrice] = useState<string>('');
  const [calcCost, setCalcCost] = useState<string>('');
  const [calcDiscount, setCalcDiscount] = useState<string>('');
  const [calcQty, setCalcQty] = useState<string>('1');
  const [calcTax, setCalcTax] = useState<string>('');

  // Filter Clients
  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
        c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
        c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  // Click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsClientDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Sync bonus product name when "Same" is selected
  useEffect(() => {
    if (negotiationType === 'bonus' && bonusType === 'same') {
        setBonusProduct(productName);
    }
  }, [productName, negotiationType, bonusType]);

  // When switching to discount mode, pre-fill target price with current price if empty
  useEffect(() => {
      if (negotiationType === 'discount' && !targetPrice && pricePalm) {
          setTargetPrice(pricePalm);
      }
  }, [negotiationType, pricePalm]);

  // --- GENERATOR CALCULATIONS ---
  const genStats = useMemo(() => {
      const qty = parseInt(quantity) || 0;
      const price = parseFloat(pricePalm.replace(',', '.')) || 0;
      const totalValueSystem = qty * price;

      let finalPrice = price;
      let investmentPercent = 0;
      let bonusValueTotal = 0;

      if (negotiationType === 'bonus') {
          const bonusCount = parseInt(bonusQty) || 0;

          if (bonusType === 'same') {
              // Same Product Logic: Weighted Average
              // Customer gets (Qty + Bonus) for the price of (Qty)
              const totalUnits = qty + bonusCount;
              finalPrice = totalUnits > 0 ? totalValueSystem / totalUnits : price;
              bonusValueTotal = bonusCount * price;
              // Investment: Free Goods Value / Total Potential Value (Trade Std) OR Free / Paid
              investmentPercent = qty > 0 ? (bonusCount / qty) * 100 : 0; 
          } else {
              // Different Product Logic
              // Customer pays for Main Product. Gets Other Product free.
              // Effective Price = (Total Paid - Value of Free Item) / Qty Main
              // This represents the "Net Cost" per unit of the main item given the gained value.
              const otherPrice = parseFloat(bonusProductPrice.replace(',', '.')) || 0;
              bonusValueTotal = bonusCount * otherPrice;

              // Effective price of main item considering the "Cashback" value of the bonus
              finalPrice = qty > 0 ? (totalValueSystem - bonusValueTotal) / qty : 0;

              // Investment % relative to the main deal
              investmentPercent = totalValueSystem > 0 ? (bonusValueTotal / totalValueSystem) * 100 : 0;
          }

      } else {
          // Discount Mode
          const target = parseFloat(targetPrice.replace(',', '.')) || price;
          finalPrice = target;

          // Investment: Discount % off the list price
          investmentPercent = price > 0 ? ((price - target) / price) * 100 : 0;
          bonusValueTotal = (price - target) * qty; // Total discount value given
      }

      return {
          totalValueSystem,
          finalPrice,
          investmentPercent,
          bonusValueTotal,
