      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsClientDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Sync bonus product name when "Same" is selected
  useEffect(() => {
    if (negotiationType === 'bonus' && bonusType === 'same') {
        setBonusProduct(productName);
    }
  }, [productName, negotiationType, bonusType]);

  // When switching to discount mode, pre-fill target price with current price if empty
  useEffect(() => {
      if (negotiationType === 'discount' && !targetPrice && pricePalm) {
          setTargetPrice(pricePalm);
      }
  }, [negotiationType, pricePalm]);

  // --- GENERATOR CALCULATIONS ---
  const genStats = useMemo(() => {
      const qty = parseInt(quantity) || 0;
      const price = parseFloat(pricePalm.replace(',', '.')) || 0;
      const totalValueSystem = qty * price;

      let finalPrice = price;
      let investmentPercent = 0;
      let bonusValueTotal = 0;

      if (negotiationType === 'bonus') {
          const bonusCount = parseInt(bonusQty) || 0;

          if (bonusType === 'same') {
              // Same Product Logic: Weighted Average
              // Customer gets (Qty + Bonus) for the price of (Qty)
              const totalUnits = qty + bonusCount;
              finalPrice = totalUnits > 0 ? totalValueSystem / totalUnits : price;
              bonusValueTotal = bonusCount * price;
              // Investment: Free Goods Value / Total Potential Value (Trade Std) OR Free / Paid
              investmentPercent = qty > 0 ? (bonusCount / qty) * 100 : 0; 
