                                    ) : (
                                        <div>
                                            <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Produto Bonificado</label>
                                            <input 
                                                type="text" 
                                                value={bonusProduct}
                                                readOnly
                                                className="w-full px-3 py-2.5 bg-white/5 border border-white/10 rounded-xl text-xs text-white/50 outline-none cursor-not-allowed truncate"
                                            />
                                        </div>
                                    )}
                                </div>

                                {/* Row 2: Name (Only for Different Product) */}
                                {bonusType === 'different' && (
                                    <div className="animate-in fade-in slide-in-from-bottom-2">
