                                        <input 
                                            type="text" 
                                            value={bonusProduct}
                                            onChange={(e) => setBonusProduct(e.target.value)}
                                            placeholder="Ex: 0000 - CHOCO BISCUIT"
                                            className="w-full px-3 py-2.5 bg-white/10 border border-white/10 rounded-xl text-xs text-white outline-none focus:border-emerald-500 placeholder-white/30"
