          bonusType: bonusType,
          bonusQty: parseInt(bonusQty) || 0,
          targetPrice: parseFloat(targetPrice.replace(',', '.')) || 0
      };

      setHistory(prev => {
          // Keep only last 50 items to manage storage size
          const newHistory = [...prev, newItem].slice(-50);
          return newHistory;
      });
  };

  const generateText = () => {
