              key = `bonus-${item.quantity}-${item.bonusQty}`;
          } else if (item.negotiationType === 'discount' && item.pricePalm > 0 && item.targetPrice > 0) {
              const discount = ((item.pricePalm - item.targetPrice) / item.pricePalm) * 100;
              const cleanDisc = (Math.round(discount * 2) / 2).toFixed(1).replace('.0', '');
              if (parseFloat(cleanDisc) > 0) {
                  label = `${cleanDisc}% OFF`;
                  key = `disc-${cleanDisc}`;
              }
          }

          if (label && !presetsMap.has(key)) {
              presetsMap.set(key, { label, item });
          }
      });

      return Array.from(presetsMap.values()).slice(0, 5);
  }, [history]);


  // Filter Clients
  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
        c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
        c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  // Filter Products
  const filteredProducts = useMemo(() => {
      if (!productName) return quickCatalog.slice(0, 8);
      return quickCatalog.filter(p => 
          p.name.toLowerCase().includes(productName.toLowerCase()) || 
          p.code.includes(productName)
      ).slice(0, 10);
  }, [productName, quickCatalog]);

  // Click outside logic
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (clientDropdownRef.current && !clientDropdownRef.current.contains(event.target as Node)) setIsClientDropdownOpen(false);
      if (productDropdownRef.current && !productDropdownRef.current.contains(event.target as Node)) setIsProductDropdownOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Sync bonus product
  useEffect(() => {
    if (negotiationType === 'bonus' && bonusType === 'same') setBonusProduct(productName);
  }, [productName, negotiationType, bonusType]);

  // Sync target price default
  useEffect(() => {
      if (negotiationType === 'discount' && !targetPrice && pricePalm) setTargetPrice(pricePalm);
  }, [negotiationType, pricePalm]);

  // --- GENERATOR CALCULATIONS ---
  const genStats = useMemo(() => {
      const qty = parseInt(quantity) || 0;
      const price = parseFloat(pricePalm.replace(',', '.')) || 0;
      const totalValueSystem = qty * price;

      let finalPrice = price;
      let investmentPercent = 0;
      let bonusValueTotal = 0;

      if (negotiationType === 'bonus') {
          const bonusCount = parseInt(bonusQty) || 0;
          if (bonusType === 'same') {
              const totalUnits = qty + bonusCount;
              finalPrice = totalUnits > 0 ? totalValueSystem / totalUnits : price;
              bonusValueTotal = bonusCount * price;
              investmentPercent = qty > 0 ? (bonusCount / qty) * 100 : 0; 
          } else {
              const otherPrice = parseFloat(bonusProductPrice.replace(',', '.')) || 0;
              bonusValueTotal = bonusCount * otherPrice;
              finalPrice = qty > 0 ? (totalValueSystem - bonusValueTotal) / qty : 0;
              investmentPercent = totalValueSystem > 0 ? (bonusValueTotal / totalValueSystem) * 100 : 0;
          }
      } else {
          const target = parseFloat(targetPrice.replace(',', '.')) || price;
          finalPrice = target;
          investmentPercent = price > 0 ? ((price - target) / price) * 100 : 0;
          bonusValueTotal = (price - target) * qty; 
      }

      return {
          totalValueSystem,
          finalPrice,
          investmentPercent,
          bonusValueTotal,
          isNegative: finalPrice < 0
      };
  }, [quantity, pricePalm, bonusQty, targetPrice, negotiationType, bonusType, bonusProductPrice]);

  // --- SIMPLE CALCULATOR CALCULATIONS ---
  const calcStats = useMemo(() => {
    const price = parseFloat(calcListPrice.replace(',', '.')) || 0;
    const unitCost = parseFloat(calcCost.replace(',', '.')) || 0;
    const disc = parseFloat(calcDiscount.replace(',', '.')) || 0;
    const qty = parseInt(calcQty) || 1;
    const taxRate = parseFloat(calcTax.replace(',', '.')) || 0;

    const discountValue = price * (disc / 100);
    const finalUnitPrice = price - discountValue;
    const taxValue = finalUnitPrice * (taxRate / 100);
    const netUnitPrice = finalUnitPrice - taxValue;

    const totalDealValue = finalUnitPrice * qty;
    const marginValue = (netUnitPrice - unitCost) * qty;
    const marginPercent = finalUnitPrice > 0 ? (marginValue / totalDealValue) * 100 : 0;

    return { price, finalUnitPrice, totalDealValue, discountValue, marginValue, marginPercent, netUnitPrice };
  }, [calcListPrice, calcCost, calcDiscount, calcQty, calcTax]);

  const handleClientSelect = (client: Client) => {
      setSelectedClient(client);
      setClientSearch(`${client.code} - ${client.name}`);
      setIsClientDropdownOpen(false);
  };

  const handleProductSelect = (prod: { name: string, price: number }) => {
      setProductName(prod.name);
      setPricePalm(prod.price.toString());
      setIsProductDropdownOpen(false);
  };

  const applyPreset = (preset: { label: string, item: NegotiationHistoryItem }) => {
      const { item } = preset;
      const basePrice = parseFloat(pricePalm.replace(',', '.')) || 0;
      setNegotiationType(item.negotiationType);
      setQuantity(item.quantity.toString());

      if (item.negotiationType === 'bonus') {
          setBonusType(item.bonusType);
          setBonusQty(item.bonusQty.toString());
          if (item.bonusType === 'different') {
              setBonusProduct(''); 
              setBonusProductPrice('');
          }
      } 
      else if (item.negotiationType === 'discount' && basePrice > 0) {
          if (item.pricePalm > 0 && item.targetPrice > 0) {
              const discountPercent = (item.pricePalm - item.targetPrice) / item.pricePalm;
              const newTarget = basePrice * (1 - discountPercent);
              setTargetPrice(newTarget.toFixed(2));
          } else {
              setTargetPrice(item.targetPrice.toString()); 
          }
      }
  };

  const saveToHistory = () => {
      const newItem: NegotiationHistoryItem = {
          id: Date.now().toString(),
          timestamp: Date.now(),
          productName: productName,
          productCode: productName.split('-')[0].trim(),
          pricePalm: parseFloat(pricePalm.replace(',', '.')) || 0,
          negotiationType: negotiationType,
          quantity: parseInt(quantity) || 0,
          bonusType: bonusType,
          bonusQty: parseInt(bonusQty) || 0,
          targetPrice: parseFloat(targetPrice.replace(',', '.')) || 0
      };
      setHistory(prev => {
          const newHistory = [...prev, newItem].slice(-50);
          return newHistory;
      });
  };

  const generateText = () => {
      if (!selectedClient) {
          alert("Selecione um cliente");
          return;
      }
      saveToHistory();
      const qty = parseInt(quantity) || 0;
      let actionBlock = '';
      if (negotiationType === 'bonus') {
          actionBlock = `
Tipo de Ação: BONIFICAÇÃO (${bonusType === 'same' ? 'Mesmo Produto' : 'Produto Cruzado'})
Produto Bonificado: ${bonusProduct.toUpperCase() || productName.toUpperCase()}
Quantidade bonificada: ${bonusQty} Und
Valor Bonificação: R$ ${genStats.bonusValueTotal.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Investimento: ${genStats.investmentPercent.toFixed(1)}%
Preço Médio/Final: R$ ${genStats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2})}`;
      } else {
          actionBlock = `
Tipo de Ação: DESCONTO EM PREÇO
Preço Tabela: R$ ${(parseFloat(pricePalm.replace(',', '.'))||0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Preço Solicitado: R$ ${genStats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Desconto Aplicado: ${genStats.investmentPercent.toFixed(1)}%
Investimento Total: R$ ${genStats.bonusValueTotal.toLocaleString('pt-BR', {minimumFractionDigits: 2})}`;
      }

      const text = `
Código/Produto: ${productName.toUpperCase()}
Quantidade: ${qty}
Valor Tabela Total: R$ ${genStats.totalValueSystem.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
Preço Sistema Unit.: R$ ${(parseFloat(pricePalm.replace(',', '.'))||0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}

*Ação Comercial*
${actionBlock.trim()}

Preço Final Cliente: R$ ${genStats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2})}

Código/Razão do Cliente: ${selectedClient.name.toUpperCase()}
`.trim();
      setGeneratedText(text);
  };

  const copyToClipboard = () => {
      navigator.clipboard.writeText(generatedText);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
  };

  const clearGenForm = () => {
      setClientSearch(''); setSelectedClient(null); setProductName(''); setQuantity(''); setPricePalm(''); setBonusQty('0'); setBonusProduct(''); setBonusProductPrice(''); setTargetPrice(''); setGeneratedText('');
  };

  const clearCalcForm = () => {
      setCalcListPrice(''); setCalcCost(''); setCalcDiscount(''); setCalcQty('1'); setCalcTax('');
  };

  const getMarginColor = (percent: number) => {
      if (percent < 10) return 'text-red-600 bg-red-50 dark:bg-red-900/20';
      if (percent < 25) return 'text-amber-600 bg-amber-50 dark:bg-amber-900/20';
      return 'text-emerald-600 bg-emerald-50 dark:bg-emerald-900/20';
  };

  // STEPPER HANDLERS
  const incrementQty = () => setQuantity(prev => (parseInt(prev || '0') + 1).toString());
  const decrementQty = () => setQuantity(prev => Math.max(0, parseInt(prev || '0') - 1).toString());
  const incrementBonus = () => setBonusQty(prev => (parseInt(prev || '0') + 1).toString());
  const decrementBonus = () => setBonusQty(prev => Math.max(0, parseInt(prev || '0') - 1).toString());

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-300 pb-32">

      {/* Header & Tabs */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <Handshake className="text-brand-600" /> Negociação
            </h2>
            <p className="text-sm text-slate-500">Ferramentas de apoio à venda</p>
        </div>
        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl overflow-x-auto scrollbar-hide">
            <button 
                onClick={() => setActiveTab('generator')}
                className={`flex-1 md:flex-none whitespace-nowrap px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'generator' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}
            >
                Gerador de Ação
            </button>
            <button 
                onClick={() => setActiveTab('calculator')}
                className={`flex-1 md:flex-none whitespace-nowrap px-4 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'calculator' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-500'}`}
            >
                Calculadora Simples
            </button>
        </div>
      </div>

      {activeTab === 'generator' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

              {/* LEFT: INPUT FORM */}
              <div className="space-y-6 animate-in slide-in-from-left-4">
                  {/* 1. Client Selection */}
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative z-20">
                      <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3 flex items-center gap-2">
                          <User size={14}/> Cliente
                      </h3>
                      <div className="relative" ref={clientDropdownRef}>
                          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                          <input 
                              type="text" 
                              value={clientSearch}
                              onChange={(e) => {
                                  setClientSearch(e.target.value);
                                  setIsClientDropdownOpen(true);
                                  if (selectedClient && e.target.value !== selectedClient.name) setSelectedClient(null);
                              }}
                              onFocus={() => setIsClientDropdownOpen(true)}
                              placeholder="Buscar cliente (Nome ou Código)..."
                              className={`w-full pl-9 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border ${selectedClient ? 'border-emerald-500 ring-1 ring-emerald-500' : 'border-slate-200 dark:border-slate-800'} rounded-xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-medium`}
                          />
                          {selectedClient && (
                              <div className="absolute right-3 top-1/2 -translate-y-1/2 text-emerald-600">
                                  <Check size={16} />
                              </div>
                          )}

                          {/* Dropdown List */}
                          {isClientDropdownOpen && (
                              <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-h-60 overflow-y-auto custom-scrollbar z-30">
                                  {filteredClients.length > 0 ? (
                                      filteredClients.map(client => (
                                          <button
                                              key={client.id}
                                              onClick={() => handleClientSelect(client)}
                                              className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 transition-colors"
                                          >
                                              <p className="font-bold text-sm text-slate-900 dark:text-white">{client.name}</p>
                                              <p className="text-xs text-slate-500">#{client.code} • {client.city}</p>
                                          </button>
                                      ))
                                  ) : (
                                      <div className="p-4 text-center text-xs text-slate-400">Nenhum cliente encontrado.</div>
                                  )}
                              </div>
                          )}
                      </div>
                  </div>

                  {/* 2. Product Data */}
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative z-10">
                      <div className="flex justify-between items-center mb-3">
                          <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                              <Package size={14}/> Produto & Preço
                          </h3>

                          {/* DYNAMIC PRESETS */}
                          <div className="flex gap-1 overflow-x-auto scrollbar-hide max-w-[200px]">
                              {actionPresets.length > 0 ? (
                                  actionPresets.map((preset, idx) => (
                                      <button 
                                        key={idx}
                                        onClick={() => applyPreset(preset)} 
                                        className="px-2 py-1 rounded bg-slate-100 dark:bg-slate-800 text-[9px] font-bold text-slate-600 dark:text-slate-400 hover:bg-emerald-50 hover:text-emerald-600 transition-colors whitespace-nowrap border border-slate-200 dark:border-slate-700 flex items-center gap-1" 
                                        title={`Usar ação: ${preset.label}`}
                                      >
                                          <Zap size={8} className="text-amber-500" /> {preset.label}
                                      </button>
                                  ))
                              ) : (
                                  <span className="text-[9px] text-slate-400 italic">Gere negociações para criar atalhos</span>
                              )}
                          </div>
                      </div>

                      <div className="space-y-3">
                          <div className="relative" ref={productDropdownRef}>
                              <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Código / Produto</label>
                              <input 
                                  type="text" 
                                  value={productName}
                                  onChange={(e) => {
                                      setProductName(e.target.value);
                                      setIsProductDropdownOpen(true);
                                  }}
                                  onFocus={() => setIsProductDropdownOpen(true)}
                                  placeholder="Digite ou selecione do histórico..."
                                  className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none focus:border-brand-500 placeholder-slate-400"
                              />

                              {/* Quick Catalog Dropdown */}
                              {isProductDropdownOpen && filteredProducts.length > 0 && (
                                  <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-h-48 overflow-y-auto custom-scrollbar z-20">
                                      <div className="px-3 py-2 text-[10px] font-bold text-slate-400 uppercase bg-slate-50 dark:bg-slate-950 border-b border-slate-100 dark:border-slate-800 flex items-center gap-1">
                                          <History size={10} /> Histórico Recente
                                      </div>
                                      {filteredProducts.map((prod, idx) => (
                                          <button
                                              key={idx}
                                              onClick={() => handleProductSelect(prod)}
                                              className="w-full text-left px-4 py-2 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 transition-colors flex justify-between items-center"
                                          >
                                              <div>
                                                  <span className="text-xs font-bold block text-slate-700 dark:text-slate-300">{prod.name}</span>
                                                  <span className="text-[10px] text-slate-400">{prod.code}</span>
                                              </div>
                                              <span className="text-xs font-bold text-emerald-600">R$ {prod.price.toFixed(2)}</span>
                                          </button>
                                      ))}
                                  </div>
                              )}
                          </div>

                          <div className="grid grid-cols-2 gap-3">
                              <div>
                                  <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Quantidade</label>
                                  <div className="flex items-center gap-1">
                                      <button onClick={decrementQty} className="w-8 h-[42px] flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-l-xl text-slate-500 hover:text-slate-700"><Minus size={14} /></button>
                                      <input 
                                          type="number" 
                                          value={quantity}
                                          onChange={(e) => setQuantity(e.target.value)}
                                          placeholder="10"
                                          className="w-full h-[42px] bg-slate-50 dark:bg-slate-950 border-y border-slate-200 dark:border-slate-800 text-center text-sm font-bold outline-none focus:border-brand-500"
                                      />
                                      <button onClick={incrementQty} className="w-8 h-[42px] flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-r-xl text-slate-500 hover:text-slate-700"><Plus size={14} /></button>
                                  </div>
                              </div>
                              <div>
                                  <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Preço Tabela (R$)</label>
                                  <div className="relative">
                                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">R$</span>
                                      <input 
                                          type="number" 
                                          value={pricePalm}
                                          onChange={(e) => setPricePalm(e.target.value)}
                                          placeholder="16,12"
                                          className="w-full pl-8 pr-3 h-[42px] bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-sm font-bold outline-none focus:border-brand-500"
                                      />
                                  </div>
                              </div>
                          </div>
                      </div>
                  </div>

                  {/* 3. Condition / Action */}
                  <div className="bg-gradient-to-br from-slate-900 to-slate-800 p-5 rounded-2xl shadow-lg text-white">
                      <div className="flex items-center justify-between mb-4">
                          <h3 className="text-xs font-bold text-emerald-400 uppercase tracking-widest flex items-center gap-2">
                              <DollarSign size={14}/> Condição Comercial
                          </h3>
                      </div>

                      {/* LARGE TOGGLE: BONUS VS DISCOUNT */}
                      <div className="flex bg-slate-950/50 p-1 rounded-xl border border-white/10 mb-4">
                          <button 
                            onClick={() => setNegotiationType('bonus')}
                            className={`flex-1 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-2 transition-all ${negotiationType === 'bonus' ? 'bg-emerald-500 text-white shadow-md' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}
                          >
                            <Gift size={14} /> Bonificação
                          </button>
                          <button 
                            onClick={() => setNegotiationType('discount')}
                            className={`flex-1 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-2 transition-all ${negotiationType === 'discount' ? 'bg-emerald-500 text-white shadow-md' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}
                          >
                            <Percent size={14} /> Desconto
                          </button>
                      </div>

                      <div className="space-y-3">

                          {/* BONUS MODE INPUTS */}
                          {negotiationType === 'bonus' && (
                              <div className="animate-in fade-in slide-in-from-right-2 duration-300 space-y-4">

                                {/* LARGE TOGGLE: SAME VS DIFFERENT */}
                                <div className="flex bg-white/10 p-1 rounded-xl">
                                    <button 
                                        onClick={() => setBonusType('same')}
                                        className={`flex-1 py-1.5 rounded-lg text-[10px] font-bold flex items-center justify-center gap-1.5 transition-all ${bonusType === 'same' ? 'bg-white text-slate-900 shadow-sm' : 'text-white/60 hover:text-white'}`}
                                    >
                                        <Repeat size={12} /> Mesmo Produto
                                    </button>
                                    <button 
                                        onClick={() => setBonusType('different')}
                                        className={`flex-1 py-1.5 rounded-lg text-[10px] font-bold flex items-center justify-center gap-1.5 transition-all ${bonusType === 'different' ? 'bg-white text-slate-900 shadow-sm' : 'text-white/60 hover:text-white'}`}
                                    >
                                        <Box size={12} /> Outro Produto
                                    </button>
                                </div>

                                {/* Dynamic Layout based on Type (Same vs Different) */}
                                <div className="grid grid-cols-2 gap-3">
                                    <div>
                                        <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Qtd. Bonificada</label>
                                        <div className="flex items-center gap-1">
                                            <button onClick={decrementBonus} className="w-8 h-[38px] flex items-center justify-center bg-white/10 rounded-l-xl text-white/70 hover:text-white border border-white/10 hover:bg-white/20"><Minus size={12} /></button>
                                            <input 
                                                type="number" 
                                                value={bonusQty}
                                                onChange={(e) => setBonusQty(e.target.value)}
                                                placeholder="1"
                                                className="w-full h-[38px] bg-white/5 border-y border-white/10 text-center text-sm font-bold text-white outline-none focus:border-emerald-500"
                                            />
                                            <button onClick={incrementBonus} className="w-8 h-[38px] flex items-center justify-center bg-white/10 rounded-r-xl text-white/70 hover:text-white border border-white/10 hover:bg-white/20"><Plus size={12} /></button>
                                        </div>
                                    </div>

                                    {/* Slot 2: Value (if diff) OR Name (if same) */}
                                    {bonusType === 'different' ? (
                                        <div className="animate-in fade-in slide-in-from-right">
                                            <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Valor (Unit.)</label>
                                            <div className="relative">
                                                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-white/50 text-xs font-bold">R$</span>
                                                <input 
                                                    type="number" 
                                                    value={bonusProductPrice}
                                                    onChange={(e) => setBonusProductPrice(e.target.value)}
                                                    placeholder="0.00"
                                                    className="w-full pl-8 pr-3 h-[38px] bg-white/10 border border-white/10 rounded-xl text-sm font-bold text-white outline-none focus:border-emerald-500"
                                                />
                                            </div>
                                        </div>
                                    ) : (
                                        <div>
                                            <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Produto Bonificado</label>
                                            <input 
                                                type="text" 
                                                value={bonusProduct}
                                                readOnly
                                                className="w-full px-3 h-[38px] bg-white/5 border border-white/10 rounded-xl text-xs text-white/50 outline-none cursor-not-allowed truncate"
                                            />
                                        </div>
                                    )}
                                </div>

                                {/* Row 2: Name (Only for Different Product) */}
