              <div className="space-y-4 animate-in slide-in-from-right-4 pb-20 lg:pb-0">
                  <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm h-full flex flex-col">
                      <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-950/50 rounded-t-2xl">
                          <h3 className="font-bold text-sm text-slate-700 dark:text-slate-300">Resultado Gerado</h3>
                          <button 
                              onClick={copyToClipboard} 
                              disabled={!generatedText}
                              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                                  copySuccess 
                                  ? 'bg-emerald-100 text-emerald-700' 
                                  : 'bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-700 hover:border-brand-500'
                              }`}
                          >
                              {copySuccess ? <Check size={14} /> : <Copy size={14} />}
                              {copySuccess ? 'Copiado!' : 'Copiar'}
                          </button>
                      </div>

                      <div className="flex-1 p-6 relative min-h-[300px]">
                          {!generatedText ? (
                              <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 dark:text-slate-700 p-8 text-center">
                                  <FileText size={48} className="mb-4 opacity-50" />
                                  <p className="text-sm font-medium">Preencha os dados e clique em gerar para ver o resumo aqui.</p>
                              </div>
                          ) : (
                              <textarea 
                                  readOnly 
                                  value={generatedText} 
                                  className="w-full h-full resize-none bg-transparent outline-none text-sm font-mono text-slate-800 dark:text-slate-300 leading-relaxed"
                              />
                          )}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* FLOATING MOBILE SUMMARY BAR */}
      {activeTab === 'generator' && (
          <div className="md:hidden fixed bottom-16 left-0 right-0 p-4 bg-slate-900/95 backdrop-blur-md border-t border-slate-700 z-40 flex items-center justify-between shadow-[0_-4px_10px_rgba(0,0,0,0.3)] animate-in slide-in-from-bottom-full duration-500">
              <div>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mb-0.5">
                      {negotiationType === 'bonus' && bonusType === 'different' ? 'Preço Médio' : 'Preço Final'}
                  </p>
                  <p className={`text-2xl font-black leading-none tracking-tight ${genStats.isNegative ? 'text-red-400' : 'text-white'}`}>
                      R$ {genStats.finalPrice.toLocaleString('pt-BR', {minimumFractionDigits: 2, maximumFractionDigits: 2})}
                  </p>
              </div>
              <button 
                  onClick={copyToClipboard}
                  disabled={!generatedText}
                  className={`px-6 py-3 rounded-xl font-bold text-sm shadow-lg transition-all active:scale-95 flex items-center gap-2 ${
                      copySuccess ? 'bg-emerald-500 text-white' : 'bg-white text-slate-900'
                  }`}
              >
                  {copySuccess ? <Check size={18}/> : <Copy size={18}/>}
                  {copySuccess ? 'Copiado!' : 'Copiar'}
              </button>
          </div>
      )}

      {/* === CALCULATOR TAB (LEGACY) === */}
      {activeTab === 'calculator' && (
          <div className="animate-in fade-in">
              <div className="flex justify-end mb-4">
                <button 
                    onClick={clearCalcForm}
                    className="flex items-center gap-2 px-3 py-2 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-xl text-xs font-bold hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                >
                    <RotateCcw size={14} /> Limpar
                </button>
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

                {/* LEFT COLUMN: INPUTS */}
                <div className="lg:col-span-5 space-y-4">
                    <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
                        <h3 className="font-bold text-sm text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                            <Calculator size={16} /> Parâmetros
                        </h3>

                        <div className="space-y-4">
                            {/* List Price */}
                            <div>
                                <label className="text-xs font-bold text-slate-900 dark:text-white mb-1.5 block">Preço de Tabela (Unitário)</label>
                                <div className="relative">
                                    <DollarSign size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="number" 
                                        inputMode="decimal"
                                        placeholder="0.00" 
                                        value={calcListPrice}
                                        onChange={(e) => setCalcListPrice(e.target.value)}
                                        className="w-full pl-9 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 font-bold tabular-nums"
                                    />
                                </div>
                            </div>

                            {/* Cost (Optional) */}
                            <div>
                                <label className="text-xs font-bold text-slate-500 mb-1.5 block flex justify-between">
                                    <span>Custo do Produto (Opcional)</span>
                                    <span className="text-[10px] uppercase bg-slate-100 dark:bg-slate-800 px-1.5 rounded">Para Margem</span>
                                </label>
                                <div className="relative">
                                    <DollarSign size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="number" 
                                        inputMode="decimal"
                                        placeholder="0.00" 
                                        value={calcCost}
                                        onChange={(e) => setCalcCost(e.target.value)}
                                        className="w-full pl-9 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 font-medium tabular-nums"
                                    />
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                {/* Discount */}
                                <div>
                                    <label className="text-xs font-bold text-slate-900 dark:text-white mb-1.5 block">Desconto</label>
                                    <div className="relative">
                                        <Percent size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-brand-500" />
                                        <input 
                                            type="number" 
                                            inputMode="decimal"
                                            placeholder="0" 
                                            value={calcDiscount}
                                            onChange={(e) => setCalcDiscount(e.target.value)}
                                            className="w-full pl-9 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 font-bold tabular-nums text-brand-600"
                                        />
                                    </div>
                                </div>

                                {/* Quantity */}
                                <div>
                                    <label className="text-xs font-bold text-slate-900 dark:text-white mb-1.5 block">Quantidade</label>
                                    <div className="relative">
                                        <Package size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                        <input 
                                            type="number" 
                                            inputMode="numeric"
                                            placeholder="1" 
                                            value={calcQty}
                                            onChange={(e) => setCalcQty(e.target.value)}
                                            className="w-full pl-9 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 font-bold tabular-nums"
                                        />
                                    </div>
                                </div>
                            </div>

                            {/* Tax (Optional) */}
                            <div>
                                <label className="text-xs font-bold text-slate-500 mb-1.5 block flex justify-between">
                                    <span>Impostos (Opcional)</span>
                                    <span className="text-[10px] uppercase bg-slate-100 dark:bg-slate-800 px-1.5 rounded">%</span>
                                </label>
                                <input 
                                    type="number" 
                                    inputMode="decimal"
                                    placeholder="0" 
                                    value={calcTax}
                                    onChange={(e) => setCalcTax(e.target.value)}
                                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl outline-none focus:ring-2 focus:ring-brand-500 font-medium tabular-nums text-sm"
                                />
                            </div>
                        </div>
                    </div>
                </div>

                {/* RIGHT COLUMN: RESULTS */}
                <div className="lg:col-span-7 space-y-4">

                    {/* Main Result Card */}
                    <div className="bg-gradient-to-br from-slate-900 to-slate-800 text-white p-6 rounded-3xl shadow-xl">
                        <div className="flex justify-between items-start mb-6">
                            <div>
                                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-1">Preço Final Unitário</p>
                                <div className="text-4xl font-black tabular-nums tracking-tight">
                                    R$ {calcStats.finalUnitPrice.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                </div>
                            </div>
                            <div className="text-right">
                                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-1">Total do Pedido</p>
                                <div className="text-xl font-bold tabular-nums text-brand-300">
                                    R$ {calcStats.totalDealValue.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                </div>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4 border-t border-white/10 pt-4">
                            <div>
                                <p className="text-xs text-slate-400 mb-1">Desconto Aplicado</p>
                                <div className="flex items-center gap-2">
                                    <span className="text-lg font-bold text-white tabular-nums">
                                        R$ {calcStats.discountValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                    </span>
                                    {calcStats.discountValue > 0 && (
                                        <span className="text-[10px] bg-red-500/20 text-red-300 px-1.5 py-0.5 rounded flex items-center gap-1">
                                            <TrendingDown size={10} /> -{calcDiscount}%
                                        </span>
                                    )}
                                </div>
                            </div>

                            {calcStats.marginPercent !== 0 && calcCost && (
                                <div className="text-right">
                                    <p className="text-xs text-slate-400 mb-1">Margem Lucro</p>
                                    <div className="flex items-center justify-end gap-2">
                                        <span className={`text-lg font-bold tabular-nums ${calcStats.marginPercent < 0 ? 'text-red-400' : 'text-emerald-400'}`}>
                                            {calcStats.marginPercent.toFixed(1)}%
                                        </span>
                                        {calcStats.marginPercent > 0 && <TrendingUp size={14} className="text-emerald-400" />}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Breakdown Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
                            <h4 className="text-xs font-bold text-slate-500 uppercase mb-3">Detalhamento</h4>
                            <div className="space-y-2 text-sm">
                                <div className="flex justify-between">
                                    <span className="text-slate-600 dark:text-slate-400">Preço Tabela</span>
                                    <span className="font-bold text-slate-900 dark:text-white">R$ {calcStats.price.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between text-red-500">
                                    <span>Desconto</span>
                                    <span className="font-bold">- R$ {calcStats.discountValue.toFixed(2)}</span>
                                </div>
                                {parseFloat(calcTax) > 0 && (
                                    <div className="flex justify-between text-amber-600">
                                        <span>Impostos ({calcTax}%)</span>
                                        <span className="font-bold">- R$ {(calcStats.finalUnitPrice * (parseFloat(calcTax)/100)).toFixed(2)}</span>
                                    </div>
                                )}
                                <div className="border-t border-slate-100 dark:border-slate-800 pt-2 mt-2 flex justify-between font-bold">
                                    <span className="text-slate-900 dark:text-white">Preço Líquido</span>
                                    <span className="text-brand-600">R$ {calcStats.netUnitPrice.toFixed(2)}</span>
                                </div>
                            </div>
                        </div>

                        {calcCost && (
                            <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
                                <h4 className="text-xs font-bold text-slate-500 uppercase mb-3">Rentabilidade Total</h4>
                                <div className="flex flex-col items-center justify-center h-full pb-4">
                                    <div className={`text-3xl font-black tabular-nums mb-1 ${calcStats.marginValue >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                                        R$ {calcStats.marginValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                    </div>
                                    <div className={`px-3 py-1 rounded-full text-xs font-bold ${getMarginColor(calcStats.marginPercent)}`}>
                                        {calcStats.marginPercent.toFixed(1)}% Margem
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
              </div>
          </div>
      )}

    </div>
  );
};
